import useTheme from '@common/hooks/useTheme'
import flexboxStyles from '@common/styles/utils/flexbox'

import styles from './styles'

interface Props {
  label?: ReactNode
  labelProps?: TextProps
  onValueChange: (value: boolean) => void
  value: boolean
  children?: any
  style?: ViewProps['style']
  uncheckedBorderColor?: ColorValue
  checkedColor?: ColorValue
  isDisabled?: boolean
  testID?: string
  invertRowDirection?: boolean
}

const Checkbox = ({
  label,
  labelProps,
  children,
  onValueChange,
  value,
  style,
  uncheckedBorderColor,
  checkedColor,
  isDisabled,
  testID = 'checkbox',
  invertRowDirection
}: Props) => {
  const { theme } = useTheme()
  const onChange = () => {
    !!onValueChange && onValueChange(!value)
  }

  return (
    <View
      style={[
        styles.container,
        style,
        isDisabled && { opacity: 0.6 },
        invertRowDirection && flexboxStyles.directionRowReverse
      ]}
    >
      <View
        style={[
          styles.checkboxWrapper,
          invertRowDirection && {
            marginRight: 0
          }
        ]}
      >
        <TouchableOpacity
          style={[
            styles.webCheckbox,
            {
              borderColor: value
                ? checkedColor || theme.successDecorative
                : uncheckedBorderColor || theme.primaryBorder
            },
            !!value && { backgroundColor: checkedColor || theme.successDecorative }
          ]}
          testID={testID}
          onPress={onChange}
          activeOpacity={0.6}
          disabled={isDisabled}
