      <View style={flexboxStyles.flex1}>
        {label ? (
          <Text
            shouldScale={false}
            onPress={onChange}
            weight="regular"
            fontSize={12}
            {...labelProps}
          >
            {label}
          </Text>
        ) : (
          children
        )}
      </View>
    </View>
  )
}

